import React from "react";

function MoviePopup({ selectedMovie, onClose }) {
    if (!selectedMovie) return null;

    const popupPlaceholder = "https://placehold.co/600x900/181818/FFFFFF?text=No+Image+Available";

    return (
        <div className="modal-overlay" onClick={onClose}>
            <div className="modal-content" onClick={(e) => e.stopPropagation()}>
                <button className="close-button" onClick={onClose}>X</button>
                <img
                    src={selectedMovie.poster && selectedMovie.poster !== "N/A" ? selectedMovie.poster : popupPlaceholder}
                    alt={selectedMovie.title}
                    onError={(e) => {
                        e.target.onerror = null;
                        e.target.src = popupPlaceholder;
                    }}
                />
                <h2>{selectedMovie.title}</h2>
                <p>{selectedMovie.year}</p>

            </div>
        </div>
    );
}

export default MoviePopup;
